// 1. Desactivar planes previos
$stmt = $pdo->prepare("UPDATE assigned_plans SET active=0 WHERE client_id=? AND plan_type IN ('entrenamiento','nutricion') AND active=1");
$stmt->execute([$clientId]);
echo "Planes desactivados: " . $stmt->rowCount() . "\n";

// 2. Insertar plan ENTRENAMIENTO
$stmt = $pdo->prepare("INSERT INTO assigned_plans (client_id,plan_type,content,version,assigned_by,valid_from,expires_at,active,created_at) VALUES (?,?,?,?,?,?,?,?,?)");
$stmt->execute([$clientId, 'entrenamiento', $trainJson, 1, $assignedBy, $validFrom, $expiresAt, 1, $now]);
$trainId = $pdo->lastInsertId();
echo "Plan entrenamiento ID: $trainId\n";

// 3. Insertar plan NUTRICION
$stmt->execute([$clientId, 'nutricion', $nutriJson, 1, $assignedBy, $validFrom, $expiresAt, 1, $now]);
